await globalThis.setor0OSubmundo.MacroMethods.overload(actor);

const namespace = 'setor0OSubmundo';
  const user = game.user;
  const flags = foundry.utils.getProperty(user.flags, namespace);

  if (!flags) {
  ui.notifications.info("Nenhuma flag encontrada para este usuário.");
  } else {
  for (const key of Object.keys(flags)) {
  await user.unsetFlag(namespace, key);
  }
  ui.notifications.info("Flags resetadas com sucesso.");
  }

const user = game.user;
const hotbar = user.hotbar;

let updated = false;

for (const [slot, macroId] of Object.entries(hotbar)) {
  const macro = game.macros.get(macroId);
  if (!macro) {
    await user.assignHotbarMacro(null, Number(slot));
    updated = true;
  }
}

if (updated) {
  ui.notifications.info("Hotbar limpa: macros inválidas removidas.");
} else {
  ui.notifications.info("Nenhuma macro inválida encontrada na hotbar.");
}

